var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"......남겨진 자들은 이것으로 마지막인가.","JPN":"……残された者はこれで最後か。","ENG":"... Are these the last remaining?","TWN":"……留下的人只有這些了嗎。"},"stage":{"bg":"SS_SHADOW_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_SHADOW_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"들리는가. 멸망 속에 남겨져야 했던 이들이여.","JPN":"聞こえるか。滅亡の中に取り残されるべきだった者よ。","ENG":"Can you hear me? Ye who had to remain amidst the fall.","TWN":"聽見了嗎？永墮滅亡中的人啊。"},"stage":{"bg":"SS_SHADOW_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"시작은 다를지언정...... 우리는 모두 동일한 최후를 맞이하였다.","JPN":"始まりは違ったとしても……我々は皆同じ最期を迎えた。","ENG":"Though our beginnings may differ... we all met the same ends.","TWN":"即便開始不同……但結局是相同的。"},"stage":{"bg":"SS_SHADOW_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"더럽혀진 단두대에 스러지는 것이 원망스러울 테지만, 부디 안식에 들길 바라마.","JPN":"汚れし断頭台にかけられるのは恨めしいことだろうが、どうか安息があらんことを。","ENG":"Though you may rue meeting your end at the soiled guillotine, I pray you may rest in peace.","TWN":"雖然這斷頭臺已被玷污，願你們安息。"},"stage":{"bg":"SS_SHADOW_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"시련을 위해 이 일대의 남겨진 자들을 모조리 불러들였는가.","JPN":"試練のためにこの一帯の残された者たちをすべて呼び集めたのか。","ENG":"Have you called all those who yet remain for these tribulations?","TWN":"為了考驗，你沒放過這一帶的所有人是嗎？"},"stage":{"bg":"SS_SHADOW_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"한때 너와 같이 멸망을 두려워하던 희생자들이거늘......","JPN":"かつてはお前のように滅亡を恐れていた犠牲者にすぎないというのに……","ENG":"They are but victims who fear their extinction, as you once were…","TWN":"他們是曾經和你一樣是害怕滅亡的犧牲者……"},"stage":{"bg":"SS_SHADOW_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"잔혹하고 비정하도다. 타기리온의 사도여.","JPN":"残酷かつ非情極まりない、タギリオンの使徒よ。","ENG":"How cruel and heartless of you... Ye Apostle of Thagirion.","TWN":"真是殘忍無情的嗚咽者使者。"},"stage":{"bg":"SS_SHADOW_06","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>흐음......</color>","JPN":"<color=#ff3636>ふむ……</color>","ENG":"<color=#ff3636>Hmm...</color>","TWN":"<color=#ff3636>嗯……</color>"},"stage":{"bg":"SS_SHADOW_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_SHADOW_DAMAGE_DOWN"},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>어떤 하찮은 미물이 내가 선별한 짐승들을 도륙했는지 의아했다마는......</color>","JPN":"<color=#ff3636>どこぞの下等な微物が余が選別した獣を殺戮したのか気になっていたが……</color>","ENG":"<color=#ff3636>I was wondering which mere mortal dared massacre the beasts I had personally handpicked...</color>","TWN":"<color=#ff3636>我還想說是哪個不知天高地厚的傢伙，屠殺了我看上的獵物……</color>"},"stage":{"bg":"SS_SHADOW_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"아직도 겁 없이 위세를 부리고 다니는구나. 불경한 방랑자여.","JPN":"いまだ恐れもなく跳梁跋扈しているのだな、不敬な放浪者よ。","ENG":"You still strut about with such audacity. Ye insolent Wayfarer.","TWN":"看來你還是一如既往的逞威風啊。倡狂的流浪者。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"망자의 가죽을 뒤집어쓰고 안식을 거부하는 네게 그렇게 불릴 이유는 없다, 솔리키타티오.","JPN":"亡者の皮を被り安息を拒むお前にそう呼ばれる筋合はない、ソリキタティオ。","ENG":"I hardly deserve such a foul description from the likes of you, who insists on wearing the skin of the dead, Sollicitatio.","TWN":"披著亡者的皮囊拒絕安息的你，沒資格說我，索爾奇塔提奧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕께서 하사하신 이름을 함부로 입에 올리지 마라.","JPN":"王より与えられた名前を断りなく口にするのではない。","ENG":"Do not speak the name bestowed by the queen in vain.","TWN":"王賜之名，不是你能隨便提及的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"권세도 병사도 백성도 잃고, 그깟 녹슨 갑주 안에 유폐된 폐인 주제에.","JPN":"権勢も兵士も民も失い、錆びた甲冑の中に幽閉された廃人ごときが。","ENG":"You are nothing but a pathetic exile trapped in that rusty armor, stripped of all your former glory, armies, and subjects.","TWN":"你不過是失去權勢、士兵、百姓，被關在生鏽盔甲裡的廢人。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"네 몰골로 보아 그 부질없는 저항도 오래가지는 못하겠구나.","JPN":"その無様な様子では、貴様の無駄な抵抗もそう長くはもたないだろう。","ENG":"Your frail state suggests your meaningless resistance shan't last much longer.","TWN":"看你這副樣子，那些徒勞的抵抗也不會持續太久了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"허나, 이번에 발탁된 미물은 왕께서 자매의 그릇으로 눈 여겨 보신 제물.","JPN":"だが、この度抜擢された微物は王が姉妹の器として目をかけた生贄。","ENG":"Still, the queen has chosen this sacrifice as a vessel for the sister.","TWN":"但是，這次被提拔的廢物是被王視為姐妹的祭品。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"주제 넘는 간섭은 용납할 수 없다.","JPN":"おこがましい干渉は許されぬ。","ENG":"Your meddling shall not be tolerated.","TWN":"絕不允許你擅自插手!"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"......제물들이 있는 방향으로 군세를 보냈군. 이들이 전부가 아니었다는 건가.","JPN":"……生贄がいる方に軍勢を送ったな。ここにいる者がすべてではなかったということか。","ENG":"So you've sent your minions to the sacrifices. These weren't all of them.","TWN":"……你向祭品的方向派出了兵力。原來這裡不是全部兵力？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"말하지 않았느냐. 왕께서 직접 정하신 바라고.","JPN":"言ったはずだ。我が王が直接英断されたこと。","ENG":"As I've said... this was determined directly by the queen.","TWN":"我不是說了嗎。這是王親自決定的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그분의 뜻을 이루는 데 만약이란 없다.","JPN":"あの方の志を遂げることに、万が一などない。","ENG":"There are no ifs when fulfilling the king's will.","TWN":"王的意志，沒有萬一。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"하찮은 미물들은 여기 쓰러진 짐승들을 3종이라 칭하지.","JPN":"下等な微物の言葉を借りれば、ここで倒れた獣のことを第3種と呼んでいるようだな。","ENG":"The mortals call these fallen beasts Category 3.","TWN":"那些螻蟻把這裡倒下的野獸們稱作3類。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"너에게 예절을 가르쳐 주기 위해서라면......","JPN":"貴様に礼儀というものを教えるには……","ENG":"But in order to teach you some manners...","TWN":"為了教教你禮儀……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"더욱 사납고 포악한 것들이 필요하겠구나.","JPN":"さらに凶暴かつ獰猛なものが必要だろう。","ENG":"I suppose we'll need something far more ferocious.","TWN":"好像需要更兇殘的東西。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_03"},{"id":"L44_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"보라. 아직 울타리에 막혀 있으나, 왕의 가호는 충분하나니.","JPN":"見よ。今なお垣根に塞がれているものの、王の加護は十分である。","ENG":"Behold. Although it may still be fenced in, the queen's blessing is plenty.","TWN":"看吧。現在還被關在籠子裡，王的庇佑已然足夠。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"제물은 고통과 고뇌 속에서 진정한 주인 앞에 무릎을 꿇을지어다.","JPN":"生贄は苦痛と苦悩の中で、真の主の前に跪く。","ENG":"The sacrifice shall kneel before the true master amidst agony and pain.","TWN":"祭品將在痛苦和苦惱中跪拜在真正的主人面前。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그럼 어디 마음껏 발악해 보아라, 방랑자.","JPN":"それでは、思う存分あがいてみよ、放浪者よ。","ENG":"Now, do your worst, Wayfarer.","TWN":"所以盡情掙扎吧，流浪者。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"이제까지 그래왔던 것처럼.","JPN":"今までどおりにな。","ENG":"As you've always done.","TWN":"繼續你那愚蠢的行為吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};